USE simplenote_db;

START TRANSACTION;

INSERT INTO `post` (
  `user_id`,
  `title`,
  `content`,
  `images`,
  `likes_count`,
  `create_time`,
  `is_deleted`,
  `ip_location`,
  `is_video`
) VALUES
(1, '武康路晚春真的很好拍', '下班后去武康路和安福路之间慢慢走了一圈，梧桐叶已经长开了，傍晚的光线特别柔和。路口的老洋房和咖啡店门头都很出片，穿浅色衣服会更显干净。想拍街景的话建议五点半以后过去，人虽然不少，但还没到最拥挤的时候。', 'http://localhost:8080/1.jpg,http://localhost:8080/2.jpg', 36, '2026-04-13 18:20:00', 0, '上海', 0),
(2, '安福路周末散步路线分享', '最近两周末都在安福路附近溜达，感觉这条线真的很适合朋友见面或者情侣约会。可以从常熟路地铁站出来，一路逛到武康路，中间随便找家咖啡店坐一会。整体节奏很轻松，拍照、聊天、吃东西都能兼顾。', 'http://localhost:8080/2.jpg', 28, '2026-04-13 10:05:00', 0, '上海', 0),
(3, '愚园路夜里比白天更有味道', '本来只是想吃个晚饭，结果饭后沿着愚园路走了一大圈。路边小店的灯光特别温柔，晚上的街道没有白天那么吵，反而更适合慢慢看。想找不那么游客感、但又有城市氛围的散步路线，我觉得这里很稳。', 'http://localhost:8080/3.jpg', 19, '2026-04-12 21:10:00', 0, '上海', 0),
(4, '上海适合雨天待半天的商场', '今天上海一直断断续续下雨，临时去了静安寺附近的商场躲雨，结果发现还挺适合消磨半天。吃饭的选择多，楼里也有小展和快闪，室内拍照不会太单调。要是最近不知道雨天去哪里，商场加咖啡其实是个很省心的方案。', 'http://localhost:8080/4.jpg', 14, '2026-04-12 14:25:00', 0, '上海', 0),
(5, '黄浦江边骑车吹风太舒服了', '晚上去江边骑了四十分钟车，风不大，体感刚刚好。一路上看到不少人在散步、拍照、遛狗，整体氛围特别松弛。要是白天逛累了，晚上来江边收个尾很不错，尤其适合最近这种不冷不热的天气。', 'http://localhost:8080/5.jpg', 23, '2026-04-11 20:40:00', 0, '上海', 0),
(6, '上海最近很火的拍照小街', '周末跟朋友临时去了一条小街，没想到几乎每隔几十米就有人在拍照。好看的不是某一家店，而是整条路的绿意、窗框、门口座椅和路边停着的自行车。喜欢随手记录生活感画面的，可以把这种街区列进清单。', 'http://localhost:8080/6.jpg', 31, '2026-04-11 16:35:00', 0, '上海', 0),
(7, '杭州九溪徒步新手也能走', '这周去九溪走了一圈，整体难度比想象中低很多，路线也比较清晰。一路上树很多，阴凉感很足，拍照不会只有游客照那种模板感。建议穿轻便一点的鞋，带一瓶水就够，周末想找个不太累的户外路线可以试试。', 'http://localhost:8080/1.jpg,http://localhost:8080/7.jpg', 33, '2026-04-13 09:20:00', 0, '杭州', 0),
(8, '西湖边早起一小时很值', '以前总觉得西湖要避开，结果这次七点多到，整个人都改观了。人不算多，光线也刚刚好，沿湖边走一小段就很舒服。最近天气不错，真的很推荐早点去一趟，哪怕只是坐一会，也会觉得这天被拉长了。', 'http://localhost:8080/7.jpg', 26, '2026-04-12 08:15:00', 0, '杭州', 0),
(9, '杭州周末春游想去植物园', '最近总刷到大家去植物园看春天，今天自己去了以后觉得确实值得。草地、树影和小路都很适合慢慢逛，不需要特别安排路线，走到哪拍到哪就行。适合朋友一起，也适合一个人安静待半天。', 'http://localhost:8080/2.jpg', 21, '2026-04-11 11:45:00', 0, '杭州', 0),
(10, '湘湖比我想象中更松弛', '原本以为湘湖只是换个地方散步，结果实际体验比预期好很多。湖边空间大，人群没那么扎堆，拍照也不会总拍到别人。最近杭州周边想找轻松一点的去处，我会把湘湖排在挺前面的位置。', 'http://localhost:8080/3.jpg', 17, '2026-04-10 15:00:00', 0, '杭州', 0),
(1, '杭州雨天去书店也很幸福', '今天杭州下雨，本来准备取消出门，后来还是去了家独立书店坐了两个小时。窗边位置很安静，听雨声翻书真的很治愈。要是最近在找雨天能待住、又不想太商业化的地方，书店加附近小店的组合很合适。', 'http://localhost:8080/4.jpg', 12, '2026-04-09 16:20:00', 0, '杭州', 0),
(2, '法喜寺附近春天太有氛围', '不是那种必须打卡多少机位的地方，但整体氛围真的很舒服。一路上有树影、有风、有一点点香火气，走起来会很安静。最近如果想找一个不赶时间、能慢慢感受环境的地方，我觉得法喜寺附近很值得去。', 'http://localhost:8080/5.jpg', 25, '2026-04-08 13:50:00', 0, '杭州', 0),
(3, '滨江夜跑路线分享', '晚上沿江边慢跑了五公里，风景比预期好，路也比较平整。沿途灯光不会太刺眼，整体环境很适合边跑边放空。对不想去热门景点、只想找个舒服路线活动一下的人来说，这条线挺友好的。', 'http://localhost:8080/6.jpg', 9, '2026-04-07 21:35:00', 0, '杭州', 0),
(4, '良渚真的适合慢慢逛一天', '最近周末不想跑太远，就去了良渚那边。比起高密度打卡，我更喜欢这里那种留白感，走路、看展、坐一会都很自然。适合想放慢节奏的人，也适合带外地朋友感受一点不一样的杭州。', 'http://localhost:8080/7.jpg', 16, '2026-04-06 12:05:00', 0, '杭州', 0),
(5, '雨天去看展比逛街更舒服', '今天原本准备约饭，结果因为下雨临时改去看展，没想到整个下午都过得很顺。室内温度合适，人也没有特别挤，边看边聊不会太累。最近总下雨的话，看展真的是一个很稳定的备选答案。', 'http://localhost:8080/1.jpg', 22, '2026-04-13 15:10:00', 0, '上海', 0),
(6, '适合雨天约会的室内路线', '最近一直在想雨天约会到底去哪里不尴尬，今天试了一条路线：先看展，再去附近吃饭，最后找家咖啡店坐着聊天。行程不赶，也不需要一直走路，整体体验比单纯逛商场好很多。', 'http://localhost:8080/2.jpg', 18, '2026-04-12 17:40:00', 0, '上海', 0),
(7, '商场里的快闪最近还挺好逛', '下雨天被迫进商场，本来没抱什么期待，结果正好碰到几个快闪活动，拍照和买点小东西都挺有意思。不是那种必须专程去的程度，但如果正好路过、又想找点轻松内容，还是值得顺手看看。', 'http://localhost:8080/3.jpg', 11, '2026-04-11 19:05:00', 0, '上海', 0),
(8, '周末室内去处我投展览一票', '最近连续两个周末都选了室内活动，最满意的还是展览。节奏能自己掌控，不会像热门餐厅那样一直排队，也比单纯看电影更有内容。适合天气不好时作为首选。', 'http://localhost:8080/4.jpg', 20, '2026-04-10 18:30:00', 0, '上海', 0),
(9, '南京夜里散步真的会上头', '昨晚在南京老城区散步，走着走着就完全不想回去了。路灯、梧桐、沿街的小店组合在一起特别有氛围，哪怕只是随便走，也会觉得很舒服。最近想找城市夜游路线的话，南京这类老街区很能打。', 'http://localhost:8080/5.jpg', 24, '2026-04-13 21:15:00', 0, '南京', 0),
(10, '老门东晚上的烟火气很足', '之前白天去过老门东，这次晚上去完全是另一种感觉。亮灯以后整条街都热闹起来，吃的、逛的、拍照的都不少，但又不会乱到失控。朋友来南京玩的话，晚上带去这里基本不会出错。', 'http://localhost:8080/6.jpg,http://localhost:8080/7.jpg', 29, '2026-04-12 20:10:00', 0, '南京', 0),
(1, '南京适合慢慢走的河边路线', '今天傍晚去河边走了一段，风很舒服，沿途还能看到不少本地人在散步。相比热门景点，这种路线的优点是没有太强的打卡压力，想停就停。适合下班后放空，也适合周末轻松活动。', 'http://localhost:8080/7.jpg', 13, '2026-04-11 18:00:00', 0, '南京', 0),
(2, '南京市集最近挺热闹的', '周末去逛了个市集，原本只是想看看，结果一待就是两个小时。摊位密度不算夸张，吃的、手作和小物件都比较好逛。最近想找有点生活气、又不会太正式的活动，市集会是不错的选择。', 'http://localhost:8080/1.jpg', 15, '2026-04-10 16:45:00', 0, '南京', 0),
(3, '玄武湖春天散步太稳了', '如果最近来南京又不想安排太多，我还是会推荐玄武湖。路线自由、视野开阔，而且不会给人很赶的感觉。春天傍晚尤其舒服，适合边走边聊天，也适合随手拍几张很自然的照片。', 'http://localhost:8080/2.jpg', 18, '2026-04-09 17:25:00', 0, '南京', 0),
(4, '朋友来南京我会带他去这里', '最近接待外地朋友，选了一个既能逛又能吃、还能稍微拍点照的地方。最重要的是路线简单，体验很完整，不会走得太累。对于第一次来南京的人来说，这种不需要做太多攻略的去处特别省心。', 'http://localhost:8080/3.jpg', 10, '2026-04-08 14:55:00', 0, '南京', 0),
(5, '预算不高也能有周末约会感', '这周末和朋友试了一条低预算路线，先逛公园，再买杯喝的找地方坐，最后去河边散步。花费不多，但整体氛围特别像认真过周末。感觉现在很多好玩的去处，不一定非要花很多钱。', 'http://localhost:8080/4.jpg', 27, '2026-04-07 18:50:00', 0, '上海', 0),
(6, '适合带朋友放松的周末安排', '最近发现比起赶行程，大家更喜欢松弛一点的安排。找一条好走的街区，穿插吃饭、喝咖啡、拍照和散步，其实就已经很完整了。尤其春天这种天气，简单路线反而更容易被喜欢。', 'http://localhost:8080/5.jpg', 16, '2026-04-06 10:30:00', 0, '上海', 0),
(7, '不想去景点就去社区小路逛', '今天没有去任何热门景点，只是在居民区旁边的小路慢慢走，结果意外地舒服。路边有花、有小店，也能感受到很真实的生活感。最近如果对人挤人有点疲惫，这种路线会让人舒服很多。', 'http://localhost:8080/6.jpg', 8, '2026-04-05 11:10:00', 0, '上海', 0),
(8, '春天的公园真的比商场更治愈', '下午去公园坐了很久，周围很多人在野餐、看书、遛狗，整个人都被带得慢下来。最近要是想找低门槛又不费钱的去处，我真的会优先推荐公园。尤其天气好的时候，幸福感来得特别直接。', 'http://localhost:8080/7.jpg', 21, '2026-04-04 15:40:00', 0, '杭州', 0),
(9, '杭州这条散步线适合拍人像', '今天跟朋友试了条新路线，发现很适合拍人像。树影和建筑之间的空间感很好，背景不会太乱，随手拍都挺自然。最近想拍一点生活感人像的，可以优先找这种有层次感的街道。', 'http://localhost:8080/1.jpg', 14, '2026-04-03 13:15:00', 0, '杭州', 0),
(10, '下班后一个人去散心的地方', '最近工作有点满，晚上临时出门走走，结果心情真的缓下来不少。这个地方不需要特别攻略，也不用打卡，到了以后自然就能待住。很适合一个人散心，也适合不想被安排得太满的下班夜晚。', 'http://localhost:8080/2.jpg', 12, '2026-04-02 20:20:00', 0, '杭州', 0),
(1, '周末露营广告，装备全新转卖', '不是分享去处，主要是清理一批露营装备，桌椅天幕都有，需要的可以私信。整体九成新，打包带走更划算。', 'http://localhost:8080/3.jpg', 1, '2026-04-13 09:00:00', 0, '苏州', 0),
(2, '随手发一下今天午饭', '中午点了个饭，味道还行，没什么特别的，就是想随便记录一下。', 'http://localhost:8080/4.jpg', 0, '2026-04-12 12:10:00', 0, '上海', 0),
(3, '求问明天去哪玩比较好', '最近有点想出去走走，但是还没想好去哪。如果大家有轻松一点、不用太折腾的地方也可以推荐。', 'http://localhost:8080/5.jpg', 2, '2026-04-11 22:05:00', 0, '杭州', 0),
(4, '同样的武康路我又来一遍', '今天又去了武康路，还是那些店、还是那几条路，照片也差不多。简单记录一下，没有特别新的信息。', 'http://localhost:8080/6.jpg', 3, '2026-04-10 17:10:00', 0, '上海', 0),
(5, '上海周末拍照喝咖啡一条龙', '如果只有半天时间，我最近会推荐这套组合：先去街区走走拍照，再找家安静点的咖啡店坐下。不会太赶，也不会空。尤其适合和很久没见的朋友碰面，一边逛一边聊就够了。', 'http://localhost:8080/7.jpg', 30, '2026-04-01 16:00:00', 0, '上海', 0),
(6, '杭州春天最喜欢的松弛感路线', '这阵子去了几次杭州，最喜欢的都不是特别热门的大景点，而是那种能走、能坐、能慢下来的路线。春天的杭州很适合把节奏调低一点，去公园、湖边或者树多的街区，都很容易觉得舒服。', 'http://localhost:8080/1.jpg,http://localhost:8080/2.jpg', 22, '2026-04-02 10:10:00', 0, '杭州', 0),
(7, '南京晚上适合约会的地方', '如果想找那种不需要特别隆重、但氛围又足够好的夜晚去处，我会推荐老城区加河边散步的组合。先吃饭，再慢慢走，聊天的节奏会很自然。最近天气也合适，很适合安排在周末晚上。', 'http://localhost:8080/3.jpg', 19, '2026-04-03 19:30:00', 0, '南京', 0);

COMMIT;
